const Q_PHYSICS_2012=[{"id": "objective>Physics>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Music</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject of the questions is Physics, as indicated by the 'Physics' in the question id.</div>", "topic": "INTRODUCTION"}, {"id": "objective>Physics>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to remove the error of parallax when taking measurements with a metre rule, the eye should  be focused</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slantingly towards the left on the markings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slantingly towards the right on the markings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertically downwards on the markings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vertically upwards on the markings</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To remove the error of parallax when taking measurements with a metre rule, the eye should be focused vertically downwards on the markings.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A load is pulled at a uniform speed along horizontal floor by a rope at 45° to floor. If the force in the rope is 1500N, what is the frictional force on the load?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1524N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1350N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1260N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1061N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2012/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> since the object moves at a uniform speed , the net force on the object is zero , since the acceleration is zero. <br/> N.B: A body moving with uniform speed has zero acceleration <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> - F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = 0 (Net Force = 0) <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">R</span> = 1500 cos 45° = 1500 x 0.7071 = 1060. 6  ≅  1061N. </div>", "topic": "FRICTION"}, {"id": "objective>Physics>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, OT is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.3N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">8/sin 135   = T/sin90  <br/> ∴  T = 8/sin135 × 1 = 11.3N</div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  From the velocity-time graph shown above, which of the following quantities CANNOT be determined?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Deceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Initial velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Total distance travelled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Initial acceleration</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The initial acceleration of the journey cannot be determined because there is no positive slope at the beginning.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the total distance covered by a train before coming to rest if its initial speed is 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> with a constant retardation of 0.1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4200m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3000m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Initial Speed, U = 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Retardation, a = -0.1m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Distance, s = ? <br/> Final velocity, v = ? <br/> Recall; <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as ;    <br/> 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> – 2 x 0 .1 x s  <br/>  0.2s  = 900  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">S</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">900<hr size=\"1\" />0.2</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  S = 4500m <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car starts from rest and moves with a uniform acceleration of 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> for 20s. <br/>  Calculate the distance covered at the end of the motion.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24km</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Initial velocity, U = 0 (since it starts from rest) <br/> Acceleration, a = 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>  <br/> Time, t = 20s, <br/> Distance, S = ? <br/> Recall: <br/> S = ut + ½ at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  S = 0 + ½ x 30 x 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> S = 15(400) = 6,000m = 6km <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rocket is fired from the earth's surface to a distant planet. <br/> By Newton's law of universal gravitation, the force F will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase as r reduces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase as G varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases as r increases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From newton's law of universal gravitation, <br/> F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span>  = GMm/r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> i.e. F  1/r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  Hence the force should increase with  a reduction in 'r'</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a freely suspended object is pulled to one side and released, it oscillates about the point of suspension because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acceleration is directly proportional to the displacement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motion is directed away from the equilibrium point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceleration is directly proportional to the square of the displacement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity is minimum at the equilibrium point</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An object in S.H.M oscillates about the point of suspension because the acceleration is directly proportional to the displacement from the fixed point.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object moves in a circular path of radius 0.5m with a speed of 1ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. <br/>  <br/> What is its angular velocity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Radius of path, r = 0.5m <br/> Speed, V = 1.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Angular Velocity, ω = ? <br/> Recall: V = ωr ---------------(i) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">ω</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />r</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />0.5</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2rads<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div> <br/> </div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, calculate the work done when the particle moves from x = 0m to x = 80m.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1200J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2400J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6000J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7000J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The workdone  = Area of bigger triangle  + Area of smaller triangle  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">bh</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">bh</td></tr></table></div> <br/>  =  <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>80 x80 + <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> x 40 x -40 <br/>  = 3200 - 800 <br/>  = 2400J</div>", "topic": "WORK ENERGY AND POWER : FORCE - DISTANCE CURVE"}, {"id": "objective>Physics>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above shows a wooden block just about to slide down an inclined plane whose inclination to the horizontal is α.The coefficient of frictional force between the block and the plane is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sin α</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tan α</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cot α</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cos α</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The coefficient of friction for an inclined plane is given by tan α where α is the angle of indication. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">force</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mgsinθ<hr size=\"1\" />mgcosθ</td></tr></table></div>= tanθ</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 20kg slides down an inclined plane at an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the horizontal. <br/>  The coefficient of static friction is .....[g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> mass (m) = 20kg <br/> Angle of inclination, θ = 30° <br/> Co-efficient of static friction, ϥ = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N.B:</td><td style=\"text-align:center;\">ϥ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mgsinθ<hr size=\"1\" />mgcosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">tanθ</td></tr></table></div> <br/> ϥ = tan30° = 0.577 ≈ 0.6</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block and tackle is used to raise a load of 250N through a vertical distance of 30m. What is the efficiency of the system if the work done against friction is 1500J? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">62.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">73.3%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">83.3%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">94.3%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Load, L = 250N <br/> Distance moved by load, d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 30m <br/> Workdone against friction = 1500J <br/> Efficiency  ŋ = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1)</td><td style=\"text-align:center;\">Efficiency</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">work output<hr size=\"1\" />work input</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> 2) Work input = workdone by effort = work done by friction + work done on load  <br/> 3) Work output = Workdone on load <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">work done on load<hr size=\"1\" />work done by effort</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span><hr size=\"1\" />W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>+W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> N.B: W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> + W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">f</span> = W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">E</span> {From (2)} <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">250 × 30<hr size=\"1\" />(250 × 30) + 1500</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">7500<hr size=\"1\" />9000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> E = 83.3%</div>", "topic": "SIMPLE MACHINES : EFFICIENCY OF MACHINES"}, {"id": "objective>Physics>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a load of 1kg stretches a cord by 1.2cm, what is the force constant of the cord? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">866 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">833 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">769 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">667 Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameter given: <br/> Load (L) = 1kg = 10N <br/> Extension, e = 1.2cm = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>m <br/> Force constant, k = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<hr size=\"1\" />e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />1.2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />1.2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />1.2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><hr size=\"1\" />1.2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1000<hr size=\"1\" />1.2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">833Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of volume 1m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and mass 2kg is totally immersed in a liquid of density 1 kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. <br/> Calculate its apparent weight. <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Volume (v) = 1.0m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> mass(m) = 2kg <br/> Density of liquid, ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 1kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Apparent Weight (Weight in the liquid) = ? <br/> N.B: When an object is partially or fully immersed in a fluid, it experiences a loss of weight (upthrust) which is equal to the weight of the fluid displaced - Archimedes Principle <br/> U = W - W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> ----------- (1) <br/> U = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>g ----------- (2) <br/> U = 1(1.0)(10) = 10N <br/> From (1), 10 = W - W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = W - 10 <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = mg - 10 <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> 2(10) - 10 <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 20 - 10  <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = 10N</div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure at any point in a liquid at rest depends only on the <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">depth and the density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass and the volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity and the surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface area and the viscosity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pressure of liquid, P = phg. <br/> Hence pressure at any point in a liquid at rest depends only on the depth and density <br/> </div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A balloon whose volume is 300m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>is filled with hydrogen. <br/> If the density of air is 1.3kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>,find the upthrust on the balloon. <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>] <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3000N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3800N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3900N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4200N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Volume of balloon = 300m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Density of air = 1.3kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Acceleration due to gravity, g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Upthrust, U = ? <br/> N.B: \"Air\" is the fluid in this case. <br/> From question <br/> U = ρvg -------------- (i) <br/> U = 1.3 × 300 × 10 = 3000 × 1.3 = 3900N</div>", "topic": "LIQUIDS AT REST : UPTHRUST"}, {"id": "objective>Physics>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Clinical thermometers are examples of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pressure gas thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistance thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alcohol thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mercury-in-glass thermometer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clinical thermometers are examples of mercury-in-glass thermometers. They are designed to measure body temperature in humans. They are filled with mercury which expands or contracts with the changes in temperature.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two metals P and Q are heated through the same temperature difference. If the ratio of the linear expansivities of P to Q is 2:3 and the ratio of their lengths is 3:4 respectively, the ratio of the increase in lengths of P to Q is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 : 2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 : 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 : 9</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9 : 8</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"font-weight:bold;text-decoration:underline;\"> Metal P </span> <br/> Temperature difference, Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> <br/> Linear expansivity, α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 2 (ratio) <br/> Length (Initial), L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = 3 (ratio) <br/> Increase in length, ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = ? <br/>  <br/> <span style=\"font-weight:bold;text-decoration:underline;\"> Metal Q </span> <br/> Temperature difference, Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> <br/> Linear expansivity, α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> = 3 (ratio) <br/> Length (Initial), L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> = 4 (ratio) <br/> Increase in length, ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆L<hr size=\"1\" />L∆θ</td><td style=\"text-align:center;\">--------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∆θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∆L<hr size=\"1\" />αL</td><td style=\"text-align:center;\">---------------</td><td style=\"text-align:center;\">(2)</td></tr></table></div> <br/> From the question, <br/> ∆θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> = Δθ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span> (same temperature difference) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span><hr size=\"1\" />α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />ΔL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span><hr size=\"1\" />L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">q</span></td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div></div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas is collected at 27°C and 700mmHg. <br/>  What is the volume of the gas at standard temperature and pressure? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1896.5cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1767.3cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1676.3cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1456.5cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27 + 273 = 300k. V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 700mmHg,  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ?  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 760mmHg <br/>  T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 273K ;    V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> × T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/(P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>× T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> )  <br/>  = (2000 x 700 x 273)/(760 x 300) <br/>  = 1676.3cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the temperature change when 500 J of heat is supplied to 100g of water. (Specific heat capacity of water = 4200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12.1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The heat supplied to a substance is given by the formula Q = mcΔT, where Q is the heat supplied, m is the mass, c is the specific heat capacity, and ΔT is the temperature change. Rearranging for ΔT gives ΔT = Q/(mc). Substituting the given values gives ΔT = 500/(0.1*4200) = 1.2°C. Therefore, the correct answer is 1.2°C.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT a factor that can increase the rate of evaporation of water in a lake? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in the pressure of the atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rise in temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in the average speed of the molecules of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in the kinetic energy of the molecules of water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Increase in the pressure of the atmosphere is not a factor that can increase the rate of evaporation of water in a lake.</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of heat energy required to melt completely 1kg of ice at -30°C is? (Specific heat capacity of water = 4200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.13 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.13 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.56 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.56 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Mass of ice, m = 1kg <br/> Initial temperature of ice, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = -30°C <br/> SHC of water = 4200Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> NOTE: To melt the ice, the following will happen: <br/> Ice at -30°C to Ice at 0°C → Ice at 0°C to Water at 0°C <br/> The quantity of heat energy needed for this to happen = mcΔθ + mLf <br/> Q = m(CΔθ + Lf) <br/> Note that the value of C that we need in this problem is not the specific heat capacity of water which is given, hence none of the options is correct. Another thing is that we are not given the latent heat of fusion of ice, Lf. But note that whenever you come across a question like this, the analysis provided above is what you will use. <br/> </div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. It is a rapid, constant and irregular motion of tiny particles. <br/> II. It gives evidence that tiny particles of matter called molecules exist. <br/> III. It takes place only in gases.  <br/> IV. It gives evidence that molecules are in a constant state of random motion. <br/> Which of the combinations above is correct about Brownian motion? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Brownian motion is a random motion of particles suspended in a fluid (a liquid or a gas) resulting from their collision with the fast atoms or molecules in the gas or liquid. Statement I, II and IV are correct about Brownian motion. Statement III is incorrect because Brownian motion is not only in gases, it can also occur in liquids.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER~~MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equation of a wave travelling in a horizontal direction is expressed as y = 15 sin2π/5(60t-x). What is its wavelength? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15</td><td style=\"text-align:center;\">Sin(2π)<hr size=\"1\" />5</td><td style=\"text-align:center;\">(60t</td><td style=\"text-align:center;\">–</td><td style=\"text-align:center;\">x)</td><td style=\"text-align:center;\">--------------------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> ;  <br/> Wavelength, λ = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">From:</td><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Asin2π</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">ft</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">x<hr size=\"1\" />λ</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">--------------------------</td><td style=\"text-align:center;\">(2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2π<hr size=\"1\" />5</td><td style=\"text-align:center;\">(60t)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πft</td><td style=\"text-align:center;\">------------</td><td style=\"text-align:center;\">(3)</td></tr></table></div> <br/> 60t = 5ft <br/> 60 = 5f <br/> f = 12Hz <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2π<hr size=\"1\" />5</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td><td style=\"text-align:center;\">(comparing</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">2)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />λ</td></tr></table></div> <br/> λ = 5m</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> From the diagram above, if the particles F is at a distance x from O to the right, the phase of the vibration will be different from that at O by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">πx<hr size=\"1\" />λ</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<hr size=\"1\" />2πx</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ<hr size=\"1\" />πx</td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phase of the vibration will be different from that at O by: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2πx<hr size=\"1\" />λ</td></tr></table></div> <br/> </div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors will affect the velocity of sound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An increase in the pitch of the sound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the loudness of the sound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wind travelling in the same direction of the sound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A change in the atmospheric pressure at constant temperature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind traveling in the same direction of the sound: <br/> When wind travels in the same direction as the sound, it can affect the velocity of sound by carrying sound waves forward, effectively boosting their speed relative to an observer on the ground.</div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics of a vibration that determines its intensity is the .....</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Overtone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wavelength</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amplitude</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The intensity of a vibration is determined by its amplitude. Amplitude refers to the maximum extent of a vibration or oscillation, measured from the position of equilibrium. A larger amplitude means a higher energy and thus a higher intensity.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where can a man place his face to get an enlarged image when using a concave mirror to shave?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Between the centre of curvature and the principal focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the principal focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between the principal focus and the pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the centre of curvature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To obtain a an enlarged image when using a concave mirror to share, the object should be placed between the principal focus and the pole.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : FORMATION OF IMAGES BY PLANE, CONCAVE AND CONVEX MIRRORS AND RAY DIAGRAMS"}, {"id": "objective>Physics>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pinhole camera is placed 300m in front of a building so that the image is formed on a screen 5cm from the pin hole. If the image is 2.5cm high, the height of the building will be <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Image height = 2.5cm = 0.025m   object height = ? <br/> Image distance = 5cm = 0.05cm ;Object distance = 300m. <br/> Magnification =  (Image height)/(Object height ) = (Image distance)/(Object distance) <br/> 0.025/x = 0.05/300;  <br/> x =  (300 x 0.025)/0.05 = 7.5/0.05 =  150m.</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The magnification of an object 2cm tall when placed 10cm in front of a plane mirror is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The magnification of an object in a plane mirror is always 1. This is because the image formed in a plane mirror is always the same size as the object.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES : LINEAR MAGNIFICATION"}, {"id": "objective>Physics>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">After reflection from the concave mirror, rays of light from the sun converges</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At the radius of curvature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At the focus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beyond the radius of curvature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Between the focus and radius of curvature</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rays of light from the sun are parallel and after reflection from a concave mirror, they converge at the focus. This is a property of concave mirrors.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A glass block of thickness 10cm is placed on an object. If an observer views the object vertically, the displacement of the object is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.33cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00cm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.67cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.50cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given; <br/> Thickness, (real depth), h = 10cm <br/> Refractive index of glass, n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> = 1.5 <br/> Lateral displacement, d = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(1)</td><td style=\"text-align:center;\">Refractive</td><td style=\"text-align:center;\">Index,</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Real depth<hr size=\"1\" />Apparent depth</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">η</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">r<hr size=\"1\" />a</td></tr></table></div> <br/> (2) Real depth = apparent depth + Lateral displacement <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.67cm</td></tr></table></div> <br/> From (2) <br/> 10 = 6.67 + d <br/> d = 3.33cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Rays of light travel from a less dense medium to a denser medium  <br/>  II. The angle of incidence is greater than critical angle.  <br/> III. Rays of light travel from a denser medium to a less dense medium. Which of the statements above are conditions for total internal reflection to occur?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I & II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I & III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II & III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total internal reflection occurs when light travels from a denser medium to a less dense medium (III) and the angle of incidence is greater than the critical angle (II). Therefore, the correct answer is 'II & III only'.</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of lenses is NOT applicable in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">projector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human eye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">periscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">telescope</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A periscope is an instrument for observation over, around or through an object, obstacle or condition that prevents direct line-of-sight observation from an observer's current position. It uses mirrors, not lenses, to redirect light from one path to another. Therefore, the use of lenses is not applicable in the periscope.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion of white light is the ability of white light to .....</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Penetrate air, water and glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Move in a straight line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Move around corners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Separate to its component colours</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion of white light refers to the phenomenon where white light is separated into its component colours when it passes through a prism or any other medium. This happens because different colours of light have different wavelengths and are refracted by different amounts when they pass through a medium. Therefore, the correct answer is 'Separate to its component colours'.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A newly charged 12V accumulator can easily start a car whereas eight new dry cells in series with an effective e.m.f. of 12V cannot start the same car because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The current capacity is high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The current capacity is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It cannot be re-charged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It cannot easily be connected to a car</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A 12V accumulator (lead-acid battery) can provide a high current necessary to start a car engine, while the eight dry cells in series, despite having the same voltage, typically have a lower current capacity and cannot deliver the high current required to start the car.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Six identical cells, each of e.m.f. 2V are connected in series.The effective e.m.f. of the cell is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12V</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When cells are connected in series, their effective e.m.f (electromotive force) is the sum of the e.m.f of each cell. Therefore, six cells each with an e.m.f of 2V will have an effective e.m.f of 12V.</div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fuse in an electric device is always connected to the ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Neutral side of an electric supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Earth side of an electric supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Live side of an electric supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Terminal side of an electric supply</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fuse in an electric device is always connected to the live side of an electric supply. This is because the live wire carries the current from the power source to the device. If a fault occurs, the fuse will blow and cut off the current, preventing damage to the device and reducing the risk of fire.</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle carrying a charge of 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>C enters a magnetic field at 3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at right angles to the field. If the force on this particle is 1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>N,what is the magnitude of the field?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>T</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">q = 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>C    F = 1.8x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>N;  <br/>  F = qvBsinθ  <br/> 1.8x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> = 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> x 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> x B x sin 90°  <br/> B = (1.8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>)/(1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>  x 3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  x 1) = 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>T . <br/> </div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct shape of the graph of capacity reactance X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> versus frequency F for a pure capacitor in an a.c. circuit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct shape of the graph of capacity reactance X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> versus frequency F for a pure capacitor in an a.c. circuit is:  <br/>  <br/> <img src=\"2012/cas1.png\" style=\"position:relative;max-width:100%;\"/> </div>", "topic": "SIMPLE A. C. CIRCUITS : CAPACITOR - CAPACITIVE REACTANCE"}, {"id": "objective>Physics>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The current output form of an a.c. source is given as I = 10 sin  ω t. The d.c. equivalent of the current is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.1A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.1A</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I = I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>sinωt;   I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span> = I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>/√2 =  10/√2  = 7.07  = 7.1A</div>", "topic": "SIMPLE A. C. CIRCUITS : PEAK AND R.M.S. VALUES"}, {"id": "objective>Physics>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A conductor of length 1m moves with a velocity of 50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span> to the direction of a uniform magnetic field of flux density 1.5 Wbm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>.What is the  e.m.f. induced in the conductor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">37.5V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.5V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75.0V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80.5V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electromotive force (emf) induced in a conductor moving in a magnetic field is given by the equation E = BLv sinθ, where B is the magnetic field, L is the length of the conductor, v is the velocity, and θ is the angle between the velocity and the magnetic field. In this case, the conductor is moving at an angle of 30 degrees to the field, so sinθ = sin(30) = 0.5. Substituting the given values gives E = 1.5 Wbm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> * 1m * 50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> * 0.5 = 37.5V.</div>", "topic": "ELECTROMAGNETIC INDUCTION"}, {"id": "objective>Physics>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of detecting a pin mistakenly swallowed by a child is by x–ray</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Diagnosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Therapy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Crystallography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mammography</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of detecting a pin mistakenly swallowed by a child is by x-ray is a diagnostic process. Diagnosis is the identification of the nature and cause of a certain phenomenon. In this case, the x-ray is used to diagnose or identify the location of the swallowed pin.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following particles CANNOT be deflected by both electric and magnetic fields?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alpha particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wave particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beta particles</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays cannot be deflected by both electric and magnetic fields. This is because gamma rays are a type of electromagnetic radiation, like x-rays. These rays are produced by the hottest and most energetic objects in the universe, such as neutron stars and pulsars, supernova explosions, and regions around black holes. Unlike alpha and beta particles, gamma rays are not charged and therefore do not have the properties required for deflection by electric or magnetic fields.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of radioactive material contains 1000 atoms. If its half-life is 20 seconds, the time taken for 125 atoms to remain is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20 seconds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 seconds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60 seconds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80 seconds</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Count-rate(atoms)</td><td style=\"border:1px solid black;text-align:center;\"> Period(s) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1000</td><td style=\"border:1px solid black;text-align:center;\">0 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">500</td><td style=\"border:1px solid black;text-align:center;\">20 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">250</td><td style=\"border:1px solid black;text-align:center;\">20 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">125</td><td style=\"border:1px solid black;text-align:center;\">20 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total</td><td style=\"border:1px solid black;text-align:center;\">60s</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The p-n junction diodes can act as rectifiers because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Conduct current when forward biased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conduct current  when  reverse biased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Block current when forward biased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conduct current in  both directions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The p.n junction can act as rectifier because they conduct current when forward biased. A diode allows current in only from one direction.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a reverse-biased voltage  is  applied across a  p-n  junction, the  depletion layer width is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Halved</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a reverse-biased voltage is applied to a p-n junction, the depletion layer width increases. The depletion layer is the region around the junction where there are no free charge carriers. In reverse bias, the p-side is connected to the negative terminal of the battery and the n-side to the positive terminal. This increases the potential barrier and widens the depletion layer. Therefore, the correct answer is 'Increased'.</div>", "topic": "INTRODUCTORY ELECTRONICS : DIODES"}, {"id": "objective>Physics>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Small size  <br/>  II. Low power requirement  <br/>  III. Not easily damaged by high Temperature  <br/>  IV. Highly durable  <br/>  Which of the above are the advantages of semiconductors?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of semiconductors are small size, low power requirement, and high durability. However, they are sensitive to high temperatures, making statement III incorrect. Thus, the correct options are I, II, and IV.</div>", "topic": "INTRODUCTORY ELECTRONICS"}];
